function processUsers(users: any[]) {
  let result = [];
  for (let i = 0; i < users.length; i++) {
    if (users[i] !== null && users[i] !== undefined) {
      if (users[i].status === 'active') {
        if (users[i].age >= 18) {
          let formattedName = '';
          if (users[i].firstName && users[i].lastName) {
            formattedName = users[i].firstName + ' ' + users[i].lastName;
          } else if (users[i].firstName) {
            formattedName = users[i].firstName;
          } else {
            formattedName = 'Unknown';
          }
          result.push({
            id: users[i].id,
            name: formattedName,
            email: users[i].email,
            isAdult: true,
            registeredDays: Math.floor((Date.now() - new Date(users[i].createdAt).getTime()) / 86400000)
          });
        }
      }
    }
  }
  return result;
}
