def fetch_and_process(urls):
    results = []
    for url in urls:
        try:
            try:
                response = requests.get(url, timeout=10)
                try:
                    data = response.json()
                    try:
                        validated = validate_schema(data)
                        results.append({'url': url, 'data': validated, 'status': 'success'})
                    except ValidationError as e:
                        logger.error(f'Validation failed for {url}: {e}')
                        results.append({'url': url, 'data': None, 'status': 'validation_error', 'error': str(e)})
                except json.JSONDecodeError as e:
                    logger.error(f'JSON parse failed for {url}: {e}')
                    results.append({'url': url, 'data': None, 'status': 'parse_error', 'error': str(e)})
            except requests.Timeout as e:
                logger.error(f'Timeout for {url}: {e}')
                results.append({'url': url, 'data': None, 'status': 'timeout', 'error': str(e)})
        except requests.RequestException as e:
            logger.error(f'Request failed for {url}: {e}')
            results.append({'url': url, 'data': None, 'status': 'request_error', 'error': str(e)})
    return results
