function Dashboard() {
  const [users, setUsers] = useState([]);
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);
  const [usersLoading, setUsersLoading] = useState(true);
  const [productsLoading, setProductsLoading] = useState(true);
  const [ordersLoading, setOrdersLoading] = useState(true);
  const [usersError, setUsersError] = useState(null);
  const [productsError, setProductsError] = useState(null);
  const [ordersError, setOrdersError] = useState(null);

  useEffect(() => { fetchUsers().then(setUsers).catch(setUsersError).finally(() => setUsersLoading(false)); }, []);
  useEffect(() => { fetchProducts().then(setProducts).catch(setProductsError).finally(() => setProductsLoading(false)); }, []);
  useEffect(() => { fetchOrders().then(setOrders).catch(setOrdersError).finally(() => setOrdersLoading(false)); }, []);

  return (
    <div>
      {usersLoading ? <Skeleton /> : usersError ? <Error msg={usersError} /> : <Card title="Users" count={users.length} />}
      {productsLoading ? <Skeleton /> : productsError ? <Error msg={productsError} /> : <Card title="Products" count={products.length} />}
      {ordersLoading ? <Skeleton /> : ordersError ? <Error msg={ordersError} /> : <Card title="Orders" count={orders.length} />}
    </div>
  );
}
```

