function getHttpStatusInfo(code: number): { label: string; type: 'success' | 'redirect' | 'client_error' | 'server_error'; retryable: boolean } {
  switch (code) {
    case 200: return { label: 'OK', type: 'success', retryable: false };
    case 201: return { label: 'Created', type: 'success', retryable: false };
    case 204: return { label: 'No Content', type: 'success', retryable: false };
    case 301: return { label: 'Moved Permanently', type: 'redirect', retryable: false };
    case 302: return { label: 'Found', type: 'redirect', retryable: false };
    case 304: return { label: 'Not Modified', type: 'redirect', retryable: false };
    case 400: return { label: 'Bad Request', type: 'client_error', retryable: false };
    case 401: return { label: 'Unauthorized', type: 'client_error', retryable: false };
    case 403: return { label: 'Forbidden', type: 'client_error', retryable: false };
    case 404: return { label: 'Not Found', type: 'client_error', retryable: false };
    case 409: return { label: 'Conflict', type: 'client_error', retryable: false };
    case 422: return { label: 'Unprocessable Entity', type: 'client_error', retryable: false };
    case 429: return { label: 'Too Many Requests', type: 'client_error', retryable: true };
    case 500: return { label: 'Internal Server Error', type: 'server_error', retryable: true };
    case 502: return { label: 'Bad Gateway', type: 'server_error', retryable: true };
    case 503: return { label: 'Service Unavailable', type: 'server_error', retryable: true };
    case 504: return { label: 'Gateway Timeout', type: 'server_error', retryable: true };
    default: return { label: 'Unknown', type: 'server_error', retryable: false };
  }
}
