function processOrder(orderId) {
  return getOrder(orderId).then(order => {
    return validateInventory(order.items).then(inventory => {
      if (!inventory.available) {
        throw new Error('Items out of stock');
      }
      return processPayment(order.total, order.paymentMethod).then(payment => {
        if (!payment.success) {
          throw new Error('Payment failed: ' + payment.error);
        }
        return updateOrderStatus(orderId, 'confirmed', payment.transactionId).then(updated => {
          return sendConfirmationEmail(order.customerEmail, updated).then(() => {
            return { success: true, order: updated, transactionId: payment.transactionId };
          }).catch(emailErr => {
            console.warn('Email failed but order confirmed:', emailErr);
            return { success: true, order: updated, transactionId: payment.transactionId, emailFailed: true };
          });
        });
      });
    });
  }).catch(err => {
    return { success: false, error: err.message };
  });
}
